import { requireTenantAccess } from '@/lib/auth';
import { redirect } from 'next/navigation';

export default async function ClientSettingsPage({ params }: { params: { subdomain: string } }) {
  try {
    await requireTenantAccess(params.subdomain);
  } catch (error) {
    redirect('/login');
  }

  // Buscar dados server-side
  const settings = await getMercadoPagoSettings(params.subdomain);

  return <SettingsClientComponent settings={settings} subdomain={params.subdomain} />;
}

