// Criar wrapper utilitário
export function withTenantAuth<T extends any[], R>(
  handler: (subdomain: string, ...args: T) => Promise<R>
) {
  return async (subdomain: string, ...args: T): Promise<R> => {
    await requireTenantAccess(subdomain);
    return handler(subdomain, ...args);
  };
}

